// Studentクラスの定義
class Student {
    String name;
    int age;

    // 引数名とフィールド名が同じ場合、thisで区別
    // setInfoメソッドの定義
    void setInfo(String name, int age) {
        this.name = name; // this.name = フィールド、name = 引数
        this.age = age;
    }

    // thisを使わない場合の問題
    // badSetNameメソッドの定義
    void badSetName(String name) {
        name = name; // 引数に引数を代入しているだけ！
        // フィールドは変わらない
    }

    // thisは「自分自身」を返すこともできる
    Student withName(String name) {
        this.name = name;
        return this; // メソッドチェーンに使える
    }

    void display() {
        System.out.println(name + "(" + age + "歳)");
    }
}

Student s = new Student();
s.setInfo("太郎", 20);
s.display(); // 太郎(20歳)

// メソッドチェーン
new Student().withName("花子").display(); // 花子(0歳)

