class Product {
    String name;
    int price;
    String category;

    // フルコンストラクタ
    Product(String name, int price, String category) {
        this.name = name;
        this.price = price;
        this.category = category;
    }

    // 2引数版: this()で3引数版を呼ぶ
    Product(String name, int price) {
        this(name, price, "一般"); // 先頭行で別コンストラクタを呼ぶ
    }

    // 1引数版: this()で2引数版を呼ぶ
    Product(String name) {
        this(name, 0); // チェーン: → 2引数 → 3引数
    }

    void show() {
        System.out.println(name + " ¥" + price + " [" + category + "]");
    }
}

new Product("Java入門", 2980, "書籍").show();
// Java入門 ¥2980 [書籍]

