// BankAccountクラスの定義
class BankAccount {
    private String owner;
    private int balance;

    public BankAccount(String owner, int initialBalance) {
        this.owner = owner;
        this.balance = Math.max(0, initialBalance);
    }

    // getter（読み取り専用アクセス）
    // getOwnerメソッドの定義
    public String getOwner() {
        return owner;
    }

    // getBalanceメソッドの定義
    public int getBalance() {
        return balance;
    }

    // setter（バリデーション付き書き込み）
    public void deposit(int amount) {
        // 条件分岐
        if (amount <= 0) {
            System.out.println("不正な金額");
            return;
        }
        balance += amount;
    }

    public boolean withdraw(int amount) {
        if (amount <= 0 || amount > balance) {
            System.out.println("引き出し不可");
            return false;
        }
        balance -= amount;
        return true;
    }
}
BankAccount acc = new BankAccount("太郎", 1000);
// acc.balance = -999; // コンパイルエラー！ private
acc.deposit(500);
System.out.println(acc.getBalance()); // 1500
acc.withdraw(2000); // 引き出し不可

