// Employeeクラスの定義
class Employee {
    // staticフィールド（クラス変数）: 全インスタンスで共有
    static int totalCount = 0;
    static String company = "テック株式会社";

    // インスタンスフィールド: 各オブジェクトごとに独立
    String name;
    int id;

    Employee(String name) {
        this.name = name;
        totalCount++;  // インスタンス生成のたびにカウント
        this.id = totalCount;
    }

    // staticメソッド: オブジェクトなしで呼べる
    // getTotalメソッドの定義
    static int getTotal() {
        // this.name; // コンパイルエラー！staticからインスタンスメンバは不可
        return totalCount;
    }

    // インスタンスメソッド: staticメンバにもアクセスできる
    // showメソッドの定義
    void show() {
        System.out.println(company + " " + name + " (ID:" + id + ")");
    }
}

Employee e1 = new Employee("太郎");
Employee e2 = new Employee("花子");
e1.show(); // テック株式会社 太郎 (ID:1)
e2.show(); // テック株式会社 花子 (ID:2)
