// Pointクラスの定義
class Point {
    int x, y;

    Point(int x, int y) {
        this.x = x;
        this.y = y;
    }
    @Override
    // equalsメソッドの定義
    public boolean equals(Object obj) {
        // 1. 同一オブジェクトチェック
        // 条件分岐
        if (this == obj) return true;
        // 2. null & 型チェック
        if (!(obj instanceof Point)) return false;
        // 3. フィールド比較
        Point other = (Point) obj;
        return this.x == other.x && this.y == other.y;
    }
    @Override
    // hashCodeメソッドの定義
    public int hashCode() {
        // equalsがtrueなら同じhashCodeを返す必要あり
        return 31 * x + y;
    }
    @Override
    public String toString() {
        return "(" + x + ", " + y + ")";
    }
}
Point p1 = new Point(3, 4);
Point p2 = new Point(3, 4);
Point p3 = new Point(1, 2);

System.out.println(p1 == p2);      // false（参照が異なる）
System.out.println(p1.equals(p2)); // true（値が同じ）
System.out.println(p1.equals(p3)); // false

