// パッケージ宣言（ファイルの先頭に記述）
package com.example.model;

// import文（他のパッケージのクラスを使う）
import java.util.ArrayList;
import java.util.List;
import java.time.LocalDate; // 個別import
// import java.util.*;      // ワイルドカードimport（全クラス）

public class User {
    private String name;
    private List<String> roles = new ArrayList<>();
    private LocalDate createdAt = LocalDate.now();
}

// パッケージの命名規則:
// ドメイン名を逆にした形式が慣例
// com.example.app
// jp.co.company.project

// java.lang パッケージのクラスはimport不要
// String, Integer, System, Math 等

// 完全修飾名（import不要だがコードが長くなる）
java.util.ArrayList<String> list = new java.util.ArrayList<>();

// 1. final変数: 再代入不可
final int MAX = 100;
// MAX = 200; // コンパイルエラー！

// final参照型: 参照の再代入は不可、中身の変更はOK
final List<String> list = new ArrayList<>();
list.add("OK");          // OK! 中身の変更は可能
// list = new ArrayList<>(); // コンパイルエラー！ 参照の再代入不可

// 2. finalメソッド: オーバーライド不可
class Parent {
    final void important() {
        System.out.println("変更禁止のメソッド");
    }
}
class Child extends Parent {
    // @Override
    // void important() {} // コンパイルエラー！
}

// 3. finalクラス: 継承不可
final class Immutable {
    private final int value;
    Immutable(int value) {
        this.value = value;
    }
    int getValue() { return value; }
}
